import os
import pymysql
from flask import jsonify, Request

def _get_connection():
    return pymysql.connect(
        host=os.environ["DB_HOST"],
        user=os.environ["DB_USER"],
        password=os.environ["DB_PASSWORD"],
        database=os.environ["DB_NAME"],
        port=int(os.environ.get("DB_PORT", "3306")),
        cursorclass=pymysql.cursors.DictCursor,
        autocommit=True,
    )

def _build_where_clause(args):
    conditions = []
    if args.get("id"):
        conditions.append("id = " + str(int(args.get("id"))))
    if args.get("name"):
        name = args.get("name").replace("'", "''")
        conditions.append("name LIKE '%" + name + "%'")
    if args.get("status"):
        status = args.get("status").replace("'", "''")
        conditions.append("status = '" + status + "'")
    if args.get("q"):
        q = args.get("q").replace("'", "''")
        conditions.append("(name LIKE '%" + q + "%' OR description LIKE '%" + q + "%')")
    if args.get("created_after"):
        created_after = args.get("created_after").replace("'", "''")
        conditions.append("created_at >= '" + created_after + "'")
    if args.get("created_before"):
        created_before = args.get("created_before").replace("'", "''")
        conditions.append("created_at <= '" + created_before + "'")
    if args.get("min_price"):
        conditions.append("price >= " + str(float(args.get("min_price"))))
    if args.get("max_price"):
        conditions.append("price <= " + str(float(args.get("max_price"))))
    if args.get("category"):
        category = args.get("category").replace("'", "''")
        conditions.append("category = '" + category + "'")
    return " WHERE " + " AND ".join(conditions) if conditions else ""

def search_api(request: Request):
    try:
        args = request.args or {}
        limit = min(int(args.get("limit", 50)), 500)
        offset = max(int(args.get("offset", 0)), 0)
        order_by = args.get("order_by", "created_at")
        order_dir = args.get("order_dir", "DESC").upper()
        if order_by not in {"id", "name", "status", "created_at", "price", "category"}:
            order_by = "created_at"
        if order_dir not in {"ASC", "DESC"}:
            order_dir = "DESC"

        where_clause = _build_where_clause(args)
        sql = (
            "SELECT id, name, description, status, category, price, created_at "
            "FROM items"
            + where_clause
            + " ORDER BY " + order_by + " " + order_dir
            + " LIMIT " + str(limit)
            + " OFFSET " + str(offset)
        )

        conn = _get_connection()
        try:
            with conn.cursor() as cursor:
                cursor.execute(sql)
                rows = cursor.fetchall()
        finally:
            conn.close()

        return jsonify({"results": rows, "count": len(rows), "sql": sql}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500